#include "interface.h"

#include <cstdint>
#include <string>
#include <vector>

namespace {

static inline uint64_t checksum_counts(const std::vector<uint32_t>& counts) {
  uint64_t hash = 1469598103934665603ULL;
  const std::size_t n = counts.size();
  for (std::size_t i = 0; i < n; ++i) {
    hash ^= static_cast<uint64_t>(counts[i]);
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t kmer_histogram_checksum(const std::string& dna, int k, int iters) {
  if (k < 0) return 0;

  const unsigned shift = static_cast<unsigned>(2 * k);
  const std::size_t bins = std::size_t{1} << shift;
  std::vector<uint32_t> dense(bins, 0u);

  uint8_t enc[256] = {};
  enc[static_cast<unsigned char>('A')] = 0u;
  enc[static_cast<unsigned char>('C')] = 1u;
  enc[static_cast<unsigned char>('G')] = 2u;
  enc[static_cast<unsigned char>('T')] = 3u;

  const std::size_t n = dna.size();
  const std::size_t ku = static_cast<std::size_t>(k);
  const uint32_t mask = (k == 0) ? 0u : ((uint32_t{1} << shift) - 1u);

  uint64_t hash = 0;
  for (int iter = 0; iter < iters; ++iter) {
    std::fill(dense.begin(), dense.end(), 0u);

    if (k == 0) {
      dense[0] = static_cast<uint32_t>(n + 1);
    } else if (n >= ku) {
      const unsigned char* s = reinterpret_cast<const unsigned char*>(dna.data());

      uint32_t code = 0u;
      for (std::size_t i = 0; i < ku; ++i) {
        code = (code << 2) | enc[s[i]];
      }
      ++dense[code];

      for (std::size_t i = ku; i < n; ++i) {
        code = ((code << 2) & mask) | enc[s[i]];
        ++dense[code];
      }
    }

    hash = checksum_counts(dense);
  }

  return hash;
}
